import{_ as e,o,c as r,a3 as t}from"./chunks/framework.BlfGB29P.js";const u=JSON.parse('{"title":"三十四、算法与数据结构 / 编码题","description":"","frontmatter":{"title":"三十四、算法与数据结构 / 编码题"},"headers":[],"relativePath":"34-algorithm-ds.md","filePath":"34-algorithm-ds.md","lastUpdated":null}'),n={name:"34-algorithm-ds.md"};function d(s,a,l,i,h,c){return o(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="三十四、算法与数据结构-编码题" tabindex="-1">三十四、算法与数据结构 / 编码题 <a class="header-anchor" href="#三十四、算法与数据结构-编码题" aria-label="Permalink to &quot;三十四、算法与数据结构 / 编码题&quot;">​</a></h1><h3 id="q-34-1" tabindex="-1">1. 复杂度分析：请解释大 O 表示法的含义，并说明最坏、平均、均摊复杂度的区别，以及时间与空间的权衡。 <a class="header-anchor" href="#q-34-1" aria-label="Permalink to &quot;1. 复杂度分析：请解释大 O 表示法的含义，并说明最坏、平均、均摊复杂度的区别，以及时间与空间的权衡。 {#q-34-1}&quot;">​</a></h3><p><strong>难度</strong>：★</p><p><strong>考点</strong>：复杂度基础、渐进分析、均摊分析。</p><p><strong>参考答案</strong>：大 O 描述当输入规模 n 趋于无穷时运行时间的上界增长量级，忽略常数项与低阶项，关注主导项。例如 O(n²) 表示运行时间随 n 平方级增长。最坏复杂度是给定规模下的最差输入代价（如快排在有序数组上退化为 O(n²)）；平均复杂度是所有输入分布期望代价；均摊复杂度针对一系列操作取平均（如动态数组扩容，单次可能 O(n)，但均摊 O(1)）。时间与空间常需权衡：哈希表以空间换 O(1) 查询，而原地算法省空间但可能增加时间。面试中应主动说明假设（如比较模型、随机化）。</p><p><strong>深度解析</strong>：复杂度分析帮助选型而非精确计数。写代码前先估最坏情况，避免 O(n³) 暴力。均摊常用于数据结构的 amortized 分析（splay、斐波那契堆）。常见误区是把 O(2n) 当 O(n²)，常数在 n 较小时影响显著。</p><p><strong>易错点</strong>：把 O(n log n + n) 误写为 O(n²)；混淆均摊与平均；忽略空间复杂度（递归栈、哈希占用）。</p><h4 id="f-34-1" tabindex="-1">追问： <a class="header-anchor" href="#f-34-1" aria-label="Permalink to &quot;追问： {#f-34-1}&quot;">​</a></h4><h5 id="fu-34-1" tabindex="-1">追问1：为什么动态数组 push 的均摊复杂度是 O(1)？ <a class="header-anchor" href="#fu-34-1" aria-label="Permalink to &quot;追问1：为什么动态数组 push 的均摊复杂度是 O(1)？ {#fu-34-1}&quot;">​</a></h5><p><strong>答</strong>：采用倍增扩容策略，第 i 次扩容需拷贝 2^(i-1) 个元素。对 n 次插入，总拷贝次数约为 n + n/2 + n/4 + ... &lt; 2n，故均摊到每次为 O(1)。若固定增量（如每次 +1）则退化为 O(n)。</p><h5 id="fu-34-2" tabindex="-1">追问2：大 O、大 Ω、大 Θ 有何区别？ <a class="header-anchor" href="#fu-34-2" aria-label="Permalink to &quot;追问2：大 O、大 Ω、大 Θ 有何区别？ {#fu-34-2}&quot;">​</a></h5><p><strong>答</strong>：大 O 是上界，大 Ω 是下界，大 Θ 是紧确界（上下界同阶）。算法分析用 O 估最坏，证明下界用 Ω，精确量级用 Θ。</p><h3 id="q-34-2" tabindex="-1">2. 双指针：给定 n 个非负整数表示柱状图高度，求容器最多能盛多少水（盛最多水的容器）。 <a class="header-anchor" href="#q-34-2" aria-label="Permalink to &quot;2. 双指针：给定 n 个非负整数表示柱状图高度，求容器最多能盛多少水（盛最多水的容器）。 {#q-34-2}&quot;">​</a></h3><p><strong>难度</strong>：★</p><p><strong>考点</strong>：双指针、贪心、单调性。</p><p><strong>参考答案</strong>：设左右指针 l、r 与当前面积 area = min(h[l], h[r]) * (r-l)，记录最大值。每次移动较矮的一端：因为宽度已定，移动高的一端面积只会缩小或不变，移动矮端才可能增大。循环至 l&lt;r。Java 关键代码：<code>while(l&lt;r){ int a=Math.min(h[l],h[r])*(r-l); max=Math.max(max,a); if(h[l]&lt;h[r]) l++; else r--; }</code>。返回 max。</p><p><strong>深度解析</strong>：时间 O(n)、空间 O(1)。双指针正确性基于：任意包含当前区间的更优解，必在移动矮端后出现。暴力为 O(n²)。注意高度可能为 0，面积非负。若求“接雨水”则是另一种解法（按行或按列/单调栈）。</p><p><strong>易错点</strong>：漏掉 <code>l&lt;r</code> 退出条件；误移动高端；整数溢出（高度乘距离用 int 足够，但超大输入需 long）。边界：数组长度小于 2 返回 0。</p><h4 id="f-34-2" tabindex="-1">追问： <a class="header-anchor" href="#f-34-2" aria-label="Permalink to &quot;追问： {#f-34-2}&quot;">​</a></h4><h5 id="fu-34-3" tabindex="-1">追问1：若要求返回最大面积对应的区间下标怎么办？ <a class="header-anchor" href="#fu-34-3" aria-label="Permalink to &quot;追问1：若要求返回最大面积对应的区间下标怎么办？ {#fu-34-3}&quot;">​</a></h5><p><strong>答</strong>：在更新 max 时额外记录 <code>(l, r)</code> 即可，复杂度不变。注意并面积时若有多个最优解，按题意返回首个或全部。</p><h5 id="fu-34-4" tabindex="-1">追问2：接雨水（Trapping Rain Water）与本题区别？ <a class="header-anchor" href="#fu-34-4" aria-label="Permalink to &quot;追问2：接雨水（Trapping Rain Water）与本题区别？ {#fu-34-4}&quot;">​</a></h5><p><strong>答</strong>：接雨水求所有凹陷积水总和，可用双指针（维护左右最大高度）或单调栈；盛水容器只求单个最大矩形面积。前者 O(n)，后者也是 O(n) 但逻辑不同。</p><h3 id="q-34-3" tabindex="-1">3. 滑动窗口：求字符串最长无重复字符子串的长度。 <a class="header-anchor" href="#q-34-3" aria-label="Permalink to &quot;3. 滑动窗口：求字符串最长无重复字符子串的长度。 {#q-34-3}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：滑动窗口、哈希表去重、双指针。</p><p><strong>参考答案</strong>：用 <code>HashSet</code> 或数组 cnt 维护窗口内字符。右指针 r 扩展，遇到重复则移动左指针 l 删除字符直至无重复。维护 <code>max = Math.max(max, r-l+1)</code>。Java：<code>while(r&lt;n){ while(set.contains(s[r])) set.remove(s[l++]); set.add(s[r++]); max=Math.max(max,r-l); }</code>。也可用 <code>lastSeen</code> 数组记录上次出现位置，直接 <code>l = Math.max(l, last[c]+1)</code> 跳过，避免逐字符删。</p><p><strong>深度解析</strong>：时间 O(n)（每个字符进出窗口各一次），空间 O(min(n,|Σ|))。字符集若为 ASCII 用长度 128 数组，Unicode 用 <code>HashMap</code>。优化版用 lastSeen 可做到真正单次遍历。最坏如全相同字符，窗口频繁收缩。</p><p><strong>易错点</strong>：左指针回退（必须单调不减）；忘记窗口长度用 <code>r-l</code> 还是 <code>r-l+1</code>（取决于左闭右开）；字符含中文需 Unicode 处理。</p><h4 id="f-34-3" tabindex="-1">追问： <a class="header-anchor" href="#f-34-3" aria-label="Permalink to &quot;追问： {#f-34-3}&quot;">​</a></h4><h5 id="fu-34-5" tabindex="-1">追问1：如何从返回长度改为返回子串本身？ <a class="header-anchor" href="#fu-34-5" aria-label="Permalink to &quot;追问1：如何从返回长度改为返回子串本身？ {#fu-34-5}&quot;">​</a></h5><p><strong>答</strong>：更新 max 时记录 <code>(start=l, end=r)</code> 区间，最后 <code>s.substring(start, end+1)</code>。注意 substring 左闭右开。</p><h5 id="fu-34-6" tabindex="-1">追问2：若允许最多 k 个重复字符呢（近似滑动窗口）？ <a class="header-anchor" href="#fu-34-6" aria-label="Permalink to &quot;追问2：若允许最多 k 个重复字符呢（近似滑动窗口）？ {#fu-34-6}&quot;">​</a></h5><p><strong>答</strong>：维护窗口内最大频次字符 freqMax，当 <code>窗口长度 - freqMax &gt; k</code> 时收缩左边界，否则扩展右边界，复杂度仍为 O(n)。</p><h3 id="q-34-4" tabindex="-1">4. 快慢指针：判断链表是否有环，并找出环的入口节点。 <a class="header-anchor" href="#q-34-4" aria-label="Permalink to &quot;4. 快慢指针：判断链表是否有环，并找出环的入口节点。 {#q-34-4}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：Floyd 判圈算法、双指针。</p><p><strong>参考答案</strong>：慢指针一次走 1 步、快指针走 2 步，相遇则有环。入口定位：相遇后令一指针回 head，两指针均每次 1 步，再次相遇即入口。Java：<code>while(fast!=null&amp;&amp;fast.next!=null){ slow=slow.next; fast=fast.next.next; if(slow==fast) break; }</code> 再 <code>p=head; while(p!=slow){p=p.next;slow=slow.next;}</code> 返回 p。</p><p><strong>深度解析</strong>：若有环，快指针必在 ≤ 环长内追上慢指针。设头到入口 a、入口到相遇 b、相遇再到入口 c，推导出 <code>a = (k-1)(b+c) + c</code>，故 head 与相遇点同速前进必在入口相遇。时间 O(n)、空间 O(1)。无环时快指针先到 null。</p><p><strong>易错点</strong>：快指针判空需 <code>fast!=null &amp;&amp; fast.next!=null</code>；误在第一次相遇就返回 true 而不算入口；处理单节点自环。</p><h4 id="f-34-4" tabindex="-1">追问： <a class="header-anchor" href="#f-34-4" aria-label="Permalink to &quot;追问： {#f-34-4}&quot;">​</a></h4><h5 id="fu-34-7" tabindex="-1">追问1：为什么快指针走 2 步而不是 3 步？ <a class="header-anchor" href="#fu-34-7" aria-label="Permalink to &quot;追问1：为什么快指针走 2 步而不是 3 步？ {#fu-34-7}&quot;">​</a></h5><p><strong>答</strong>：走 2 步最简单且保证必相遇（相对速度 1）。走 3 步在环长与步长不互质时可能跳过，需额外处理；且更易越界。2 步是时间复杂度与正确性的最佳折中。</p><h5 id="fu-34-8" tabindex="-1">追问2：如何求环的长度？ <a class="header-anchor" href="#fu-34-8" aria-label="Permalink to &quot;追问2：如何求环的长度？ {#fu-34-8}&quot;">​</a></h5><p><strong>答</strong>：相遇后固定慢指针，快指针继续每次 2 步，再次相遇所走步数即环长；或相遇后单步走一圈计数。</p><h3 id="q-34-5" tabindex="-1">5. 字符串匹配：在文本串 haystack 中查找模式串 needle（实现 strStr），说明 KMP 与 Rabin-Karp 思路。 <a class="header-anchor" href="#q-34-5" aria-label="Permalink to &quot;5. 字符串匹配：在文本串 haystack 中查找模式串 needle（实现 strStr），说明 KMP 与 Rabin-Karp 思路。 {#q-34-5}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：KMP 前缀函数、Rabin-Karp 滚动哈希。</p><p><strong>参考答案</strong>：暴力 O(nm)。KMP 先求 next 数组（最长真前缀=后缀）：<code>for(i=1;i&lt;m;i++){ while(j&gt;0&amp;&amp;p[i]!=p[j]) j=next[j-1]; if(p[i]==p[j]) j++; next[i]=j; }</code> 再用同逻辑在主串匹配，失配跳 next。Rabin-Karp 对模式算哈希，主串窗口滚动 <code>hash = (hash - h[l]*base^(m-1)) * base + h[r]</code>，配合模大质数防冲突，相等再逐字符校验。</p><p><strong>深度解析</strong>：KMP 最坏 O(n+m)，空间 O(m)；适合重复模式多的场景。Rabin-Karp 平均 O(n+m)，最坏 O(nm)（全冲突），但天然支持多模式（如查多个词）。哈希取 <code>mod 1e9+7</code> 并可用双哈希降冲突。</p><p><strong>易错点</strong>：next 数组下标偏移（从 0 还是 1）；滚动哈希忘记消去最高位与溢出（用 long）；base^m 预计算。</p><h4 id="f-34-5" tabindex="-1">追问： <a class="header-anchor" href="#f-34-5" aria-label="Permalink to &quot;追问： {#f-34-5}&quot;">​</a></h4><h5 id="fu-34-9" tabindex="-1">追问1：KMP 的 next 数组能不能优化（如 nextval）？ <a class="header-anchor" href="#fu-34-9" aria-label="Permalink to &quot;追问1：KMP 的 next 数组能不能优化（如 nextval）？ {#fu-34-9}&quot;">​</a></h5><p><strong>答</strong>：可进一步做 nextval：若 <code>p[next[j]] == p[j]</code>，则 nextval[j]=nextval[next[j]]，避免连续相同字符的无效跳转，减少匹配次数。</p><h5 id="fu-34-10" tabindex="-1">追问2：为什么 Rabin-Karp 需要先逐字符校验而非直接返回？ <a class="header-anchor" href="#fu-34-10" aria-label="Permalink to &quot;追问2：为什么 Rabin-Karp 需要先逐字符校验而非直接返回？ {#fu-34-10}&quot;">​</a></h5><p><strong>答</strong>：哈希冲突可能导致不同串哈希相同（即使取模大质数仍有概率）。相等时必须回退逐字符比对确认，否则会漏报/误报。</p><h3 id="q-34-6" tabindex="-1">6. 链表反转：反转单链表（迭代与递归两种写法）。 <a class="header-anchor" href="#q-34-6" aria-label="Permalink to &quot;6. 链表反转：反转单链表（迭代与递归两种写法）。 {#q-34-6}&quot;">​</a></h3><p><strong>难度</strong>：★</p><p><strong>考点</strong>：指针操作、递归/迭代。</p><p><strong>参考答案</strong>：迭代：<code>prev=null; while(cur!=null){ next=cur.next; cur.next=prev; prev=cur; cur=next; } return prev;</code>。递归：反转 <code>cur.next</code> 之后的部分，再把 <code>cur</code> 接到末尾：<code>if(head==null||head.next==null) return head; ListNode newHead=reverse(head.next); head.next.next=head; head.next=null; return newHead;</code>。</p><p><strong>深度解析</strong>：迭代 O(n)/O(1) 空间，最稳。递归 O(n)/O(n) 栈空间，链表过长会 StackOverflow。实战多为迭代。注意处理 null 与单节点。可扩展为反转 [m,n] 区间、K 个一组反转（需记录段首段尾）。</p><p><strong>易错点</strong>：循环中先保存 next 再改指针，否则断链；递归忘记把原 head.next 置 null 导致环；空链表返回 null。</p><h4 id="f-34-6" tabindex="-1">追问： <a class="header-anchor" href="#f-34-6" aria-label="Permalink to &quot;追问： {#f-34-6}&quot;">​</a></h4><h5 id="fu-34-11" tabindex="-1">追问1：如何每 K 个一组反转并连接？ <a class="header-anchor" href="#fu-34-11" aria-label="Permalink to &quot;追问1：如何每 K 个一组反转并连接？ {#fu-34-11}&quot;">​</a></h5><p><strong>答</strong>：用哨兵节点，每次定位 K 个区间，反转后连接前后段，更新前驱。注意不足 K 个时保持原序。可结合反转函数复用，复杂度 O(n)。</p><h5 id="fu-34-12" tabindex="-1">追问2：反转部分链表 [m,n] 如何实现？ <a class="header-anchor" href="#fu-34-12" aria-label="Permalink to &quot;追问2：反转部分链表 [m,n] 如何实现？ {#fu-34-12}&quot;">​</a></h5><p><strong>答</strong>：找到第 m-1 个前驱，对 m..n 区间执行反转并接回。用 dummy 头统一边界，避免 m=1 时特判。</p><h3 id="q-34-7" tabindex="-1">7. 合并与定位：合并两个有序链表；并求单链表倒数第 K 个节点。 <a class="header-anchor" href="#q-34-7" aria-label="Permalink to &quot;7. 合并与定位：合并两个有序链表；并求单链表倒数第 K 个节点。 {#q-34-7}&quot;">​</a></h3><p><strong>难度</strong>：★</p><p><strong>考点</strong>：归并、双指针、快慢指针偏移。</p><p><strong>参考答案</strong>：合并：用哨兵 dummy，比较两链表头取小者接上，最后接剩余。Java：<code>while(l1!=null&amp;&amp;l2!=null){ if(l1.val&lt;l2.val){ cur.next=l1; l1=l1.next;} else {...} cur=cur.next;} cur.next=l1!=null?l1:l2;</code>。倒数第 K：快指针先走 K 步，再快慢同速，快到尾时慢即倒数第 K。注意 K 越界返回 null。</p><p><strong>深度解析</strong>：合并 O(n+m)、空间 O(1)（不含结果）。可扩展到合并 K 个（优先队列 O(N log K) 或小顶堆）。倒数 K 用双指针避免两次遍历，O(n)/O(1)。若 K&lt;=0 或 K&gt;长度应明确返回（题目常要求返回 null 或抛异常）。</p><p><strong>易错点</strong>：合并时漏接剩余链表；倒数 K 未判 K 合法性导致空指针；快指针先走 K 步前应检查 <code>k--</code> 与边界。</p><h4 id="f-34-7" tabindex="-1">追问： <a class="header-anchor" href="#f-34-7" aria-label="Permalink to &quot;追问： {#f-34-7}&quot;">​</a></h4><h5 id="fu-34-13" tabindex="-1">追问1：合并 K 个有序链表最优做法？ <a class="header-anchor" href="#fu-34-13" aria-label="Permalink to &quot;追问1：合并 K 个有序链表最优做法？ {#fu-34-13}&quot;">​</a></h5><p><strong>答</strong>：维护大小为 K 的小顶堆，每次取最小接结果并把该节点下一节点入堆，复杂度 O(N log K)，N 为总节点数。也可用分治两两合并到 O(N log K)。</p><h5 id="fu-34-14" tabindex="-1">追问2：若要求倒数第 K 个从 1 计数且 K 超长？ <a class="header-anchor" href="#fu-34-14" aria-label="Permalink to &quot;追问2：若要求倒数第 K 个从 1 计数且 K 超长？ {#fu-34-14}&quot;">​</a></h5><p><strong>答</strong>：先让快指针走 K 步，若中途为 null 说明 K 大于长度，直接返回 null（或按约定抛 IllegalArgumentException）。</p><h3 id="q-34-8" tabindex="-1">8. LRU 缓存：设计一个 LRUCache，支持 get 和 put 均为 O(1)。 <a class="header-anchor" href="#q-34-8" aria-label="Permalink to &quot;8. LRU 缓存：设计一个 LRUCache，支持 get 和 put 均为 O(1)。 {#q-34-8}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：LRU、哈希表 + 双向链表、LinkedHashMap。</p><p><strong>参考答案</strong>：手写：维护 <code>HashMap&lt;Integer,Node&gt;</code> 与双向链表头尾哨兵。get 命中则把节点移到表头；put 命中更新值并移到表头，未命中新建节点插表头，超容量删表尾。Java 也可用 <code>LinkedHashMap</code>，重写 <code>removeEldestEntry</code> 返回 <code>size()&gt;cap</code>，accessOrder 设为 true。关键：map 存节点实现 O(1) 查找，链表维护顺序实现 O(1) 淘汰。</p><p><strong>深度解析</strong>：时间 O(1)、空间 O(cap)。手写需处理并发（面试常加 <code>synchronized</code> 或 <code>ConcurrentHashMap</code>+锁）；LinkedHashMap 实现简洁但需理解 accessOrder 语义。注意多线程下 LinkedHashMap 非线程安全。可扩展为 LFU（需频次链表/TreeMap）。</p><p><strong>易错点</strong>：移动节点忘记维护前驱后继四个指针；LinkedHashMap 未设 accessOrder=true 导致按插入序；容量边界（cap&lt;=0）。</p><h4 id="f-34-8" tabindex="-1">追问： <a class="header-anchor" href="#f-34-8" aria-label="Permalink to &quot;追问： {#f-34-8}&quot;">​</a></h4><h5 id="fu-34-15" tabindex="-1">追问1：LRU 与 LFU 区别？何时用 LFU？ <a class="header-anchor" href="#fu-34-15" aria-label="Permalink to &quot;追问1：LRU 与 LFU 区别？何时用 LFU？ {#fu-34-15}&quot;">​</a></h5><p><strong>答</strong>：LRU 淘汰最久未用，LFU 淘汰访问频次最低。缓存有热点且频率分布稳定时用 LFU 命中率更高；但 LFU 实现复杂、对新进入项不友好（需老化机制）。</p><h5 id="fu-34-16" tabindex="-1">追问2：如何用 Java 内置类一行实现？ <a class="header-anchor" href="#fu-34-16" aria-label="Permalink to &quot;追问2：如何用 Java 内置类一行实现？ {#fu-34-16}&quot;">​</a></h5><p><strong>答</strong>：<code>new LinkedHashMap&lt;K,V&gt;(cap, 0.75f, true){ protected boolean removeEldestEntry(Map.Entry e){ return size()&gt;cap; } }</code>，第三个参数 true 即 accessOrder。</p><h3 id="q-34-9" tabindex="-1">9. 二叉树遍历：实现前/中/后序遍历，分别给出递归与迭代版本。 <a class="header-anchor" href="#q-34-9" aria-label="Permalink to &quot;9. 二叉树遍历：实现前/中/后序遍历，分别给出递归与迭代版本。 {#q-34-9}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：DFS、栈模拟递归、遍历序。</p><p><strong>参考答案</strong>：递归三要素：访问根、递归左、递归右，调整顺序即前/中/后序。迭代用显式栈：前序 <code>stack.push(root)</code> 弹栈访问并先压右再压左；中序 <code>while(cur!=null||!st.empty()){ while(cur!=null){st.push(cur);cur=cur.left;} cur=st.pop(); visit; cur=cur.right;}</code>；后序可用「根右左」逆序或双栈。关键：中序最易错，需把左链全压栈。</p><p><strong>深度解析</strong>：时间 O(n)、空间 O(h)（h 树高，最坏链 O(n)）。递归简洁但深树爆栈；迭代统一模板可用「标记法」（节点入栈配 null 标记）。Morris 遍历可做到 O(1) 空间（借线索），但会改动树结构。</p><p><strong>易错点</strong>：迭代中序忘记 <code>cur=cur.right</code> 导致死循环；后序直接套前序模板顺序错；空树返回空集合而非 null。</p><h4 id="f-34-9" tabindex="-1">追问： <a class="header-anchor" href="#f-34-9" aria-label="Permalink to &quot;追问： {#f-34-9}&quot;">​</a></h4><h5 id="fu-34-17" tabindex="-1">追问1：Morris 遍历如何做到 O(1) 空间？ <a class="header-anchor" href="#fu-34-17" aria-label="Permalink to &quot;追问1：Morris 遍历如何做到 O(1) 空间？ {#fu-34-17}&quot;">​</a></h5><p><strong>答</strong>：利用叶子空指针作线索，中序时找前驱的右指针指向当前节点，遍历完再还原。不用栈，空间 O(1)，但会短暂修改树（需恢复）。</p><h5 id="fu-34-18" tabindex="-1">追问2：如何只遍历第 k 个节点提前返回？ <a class="header-anchor" href="#fu-34-18" aria-label="Permalink to &quot;追问2：如何只遍历第 k 个节点提前返回？ {#fu-34-18}&quot;">​</a></h5><p><strong>答</strong>：中序计数，访问到第 k 个立即抛自定义异常或设 flag 终止，避免遍历全部 n 个节点，O(k) 而非 O(n)。</p><h3 id="q-34-10" tabindex="-1">10. 层序遍历与最近公共祖先：层序输出二叉树每层；求两节点最近公共祖先 LCA。 <a class="header-anchor" href="#q-34-10" aria-label="Permalink to &quot;10. 层序遍历与最近公共祖先：层序输出二叉树每层；求两节点最近公共祖先 LCA。 {#q-34-10}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：BFS 队列、LCA、递归。</p><p><strong>参考答案</strong>：层序用 <code>Queue</code>：<code>while(!q.isEmpty()){ int sz=q.size(); List level=new ArrayList(); for(i=0;i&lt;sz;i++){ Node n=q.poll(); level.add(n.val); if(n.left!=null)q.offer(n.left); if(n.right!=null)q.offer(n.right);} res.add(level);}</code>。LCA（二叉搜索树用值大小分叉；普通树递归：若 root 为 p/q 或空返回 root，否则递归左右，左右都非空则 root 是 LCA，否则返回非空的那个）。</p><p><strong>深度解析</strong>：层序 O(n)/O(n)（队列最宽层）。LCA 递归 O(n)/O(h)。BST 版可降至 O(h)：当前值介于 p、q 之间即 LCA，否则往单边走。注意节点可能为祖先自身（p 是 q 祖先时 LCA 为 p）。</p><p><strong>易错点</strong>：层序忘记按层 <code>size</code> 分批导致不分层；LCA 未处理 p/q 之一为空；BST 版未处理值相等情况。</p><h4 id="f-34-10" tabindex="-1">追问： <a class="header-anchor" href="#f-34-10" aria-label="Permalink to &quot;追问： {#f-34-10}&quot;">​</a></h4><h5 id="fu-34-19" tabindex="-1">追问1：如何用父指针法求 LCA？ <a class="header-anchor" href="#fu-34-19" aria-label="Permalink to &quot;追问1：如何用父指针法求 LCA？ {#fu-34-19}&quot;">​</a></h5><p><strong>答</strong>：先 DFS 记录每个节点父指针与深度，将较深节点上移到同深，再同时上移直到相遇，相遇点即 LCA。适合需多次查询（可结合倍增优化）。</p><h5 id="fu-34-20" tabindex="-1">追问2：层序如何之字形打印（Zigzag）？ <a class="header-anchor" href="#fu-34-20" aria-label="Permalink to &quot;追问2：层序如何之字形打印（Zigzag）？ {#fu-34-20}&quot;">​</a></h5><p><strong>答</strong>：加布尔标志，偶数层正序、奇数层反转，或用双端队列交替从头/尾入队。</p><h3 id="q-34-11" tabindex="-1">11. 二叉树序列化与反序列化（Codec）。 <a class="header-anchor" href="#q-34-11" aria-label="Permalink to &quot;11. 二叉树序列化与反序列化（Codec）。 {#q-34-11}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：树的编解码、DFS/BFS、字符串协议。</p><p><strong>参考答案</strong>：前序递归：序列化时空节点用 <code>#</code> 占位、逗号分隔，<code>ser(root)</code> 返回 <code>root==null?&quot;#&quot;:root.val+&quot;,&quot;+ser(left)+ser(right)</code>。反序列化用队列/指针按前序重建：<code>if(val.equals(&quot;#&quot;)) return null; Node n=new Node(Integer.parseInt(val)); n.left=deser(); n.right=deser();</code>。也可用层序（队列 + 显式 null）编码，更直观易调试。</p><p><strong>深度解析</strong>：时间 O(n)、空间 O(n)。前序方案紧凑但依赖分隔符唯一性（值含逗号需转义）。BFS 层序方案便于按层恢复、空节点也占位。注意 Integer 范围与负数解析。反序列化需保证字符串合法。</p><p><strong>易错点</strong>：分隔符与值冲突（如值本身含 <code>,</code>）；忘记递归还原左右顺序；队列版未处理末尾多余 null。</p><h4 id="f-34-11" tabindex="-1">追问： <a class="header-anchor" href="#f-34-11" aria-label="Permalink to &quot;追问： {#f-34-11}&quot;">​</a></h4><h5 id="fu-34-21" tabindex="-1">追问1：序列化能否不存 null 占位而仍唯一还原？ <a class="header-anchor" href="#fu-34-21" aria-label="Permalink to &quot;追问1：序列化能否不存 null 占位而仍唯一还原？ {#fu-34-21}&quot;">​</a></h5><p><strong>答</strong>：不能仅靠前序无 null 唯一确定树（同前序可能有多种结构），须配合中序或显式 null/括号表示。最稳妥是带 <code>#</code> 占位或中序配对。</p><h5 id="fu-34-22" tabindex="-1">追问2：如何压缩序列化体积？ <a class="header-anchor" href="#fu-34-22" aria-label="Permalink to &quot;追问2：如何压缩序列化体积？ {#fu-34-22}&quot;">​</a></h5><p><strong>答</strong>：可用变长整数、位图标记空节点，或对满二叉树用层次编号（下标 i 的左孩子 2i+1）省略 null。实际面试以可读性优先。</p><h3 id="q-34-12" tabindex="-1">12. 堆与优先队列：从数组中找前 K 个高频元素（TopK）。 <a class="header-anchor" href="#q-34-12" aria-label="Permalink to &quot;12. 堆与优先队列：从数组中找前 K 个高频元素（TopK）。 {#q-34-12}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：小顶堆、HashMap 计数、优先级队列。</p><p><strong>参考答案</strong>：先 <code>HashMap</code> 统计频次 O(n)。维护容量为 K 的小顶堆，元素按频次比较：遍历 entry，堆未满直接入，堆满且新频次 &gt; 堆顶频次则 <code>poll</code> 再 <code>offer</code>。Java：<code>PriorityQueue&lt;Map.Entry&lt;Integer,Integer&gt;&gt; pq=(a,b)-&gt;a.getValue()-b.getValue();</code>。最后弹出得 TopK（顺序为升序，按需反转）。复杂度 O(n log K)。</p><p><strong>深度解析</strong>：比全排序 O(n log n) 优，适合 n 大 K 小。也可用快速选择（快排 partition）平均 O(n) 但最坏 O(n²)。堆法稳定且易实现。注意频次相同元素的取舍（题目常不要求稳定）。</p><p><strong>易错点</strong>：堆比较器方向写反（应用小顶堆取堆顶最小）；Integer 相减比较可能溢出（用 <code>Integer.compare</code>）；返回顺序未反转。</p><h4 id="f-34-12" tabindex="-1">追问： <a class="header-anchor" href="#f-34-12" aria-label="Permalink to &quot;追问： {#f-34-12}&quot;">​</a></h4><h5 id="fu-34-23" tabindex="-1">追问1：TopK 为什么用小顶堆而非大顶堆？ <a class="header-anchor" href="#fu-34-23" aria-label="Permalink to &quot;追问1：TopK 为什么用小顶堆而非大顶堆？ {#fu-34-23}&quot;">​</a></h5><p><strong>答</strong>：小顶堆堆顶是当前 K 个里最小，新元素更大时替换它，始终保留最大的 K 个，且弹出代价 O(log K)。大顶堆无法淘汰较小元素，需存全部再取。</p><h5 id="fu-34-24" tabindex="-1">追问2：数据量超内存怎么办（外部 TopK）？ <a class="header-anchor" href="#fu-34-24" aria-label="Permalink to &quot;追问2：数据量超内存怎么办（外部 TopK）？ {#fu-34-24}&quot;">​</a></h5><p><strong>答</strong>：分块读入，每块维护局部 TopK，再合并；或用堆+磁盘临时文件（多路归并）。本质仍是限制堆大小为 K。</p><h3 id="q-34-13" tabindex="-1">13. 堆求中位数（数据流中位数）。 <a class="header-anchor" href="#q-34-13" aria-label="Permalink to &quot;13. 堆求中位数（数据流中位数）。 {#q-34-13}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：双堆（大顶堆+小顶堆）、动态维护。</p><p><strong>参考答案</strong>：用大顶堆 <code>lo</code> 存较小一半、小顶堆 <code>hi</code> 存较大一半，保持 <code>lo.size()&gt;=hi.size()</code> 且差值 ≤1。新数：先入 <code>lo</code> 再将其顶弹入 <code>hi</code>，若 <code>hi</code> 比 <code>lo</code> 多则弹回，维持平衡。中位数：<code>lo.size()&gt;hi.size()?lo.peek():(lo.peek()+hi.peek())/2.0</code>。Java 小顶堆 <code>new PriorityQueue()</code>，大顶堆加反向比较器。</p><p><strong>深度解析</strong>：插入 O(log n)、查询 O(1)。双堆是经典「对顶堆」技巧，也可用有序集合（TreeSet）但重复值需计数。注意偶数个时取两顶均值用 double 防精度丢失。</p><p><strong>易错点</strong>：平衡条件写错导致两堆大小差超过 1；重复元素插入顺序影响哪堆；整数除法丢失小数（用 2.0）。</p><h4 id="f-34-13" tabindex="-1">追问： <a class="header-anchor" href="#f-34-13" aria-label="Permalink to &quot;追问： {#f-34-13}&quot;">​</a></h4><h5 id="fu-34-25" tabindex="-1">追问1：Sliding Window 中位数怎么做？ <a class="header-anchor" href="#fu-34-25" aria-label="Permalink to &quot;追问1：Sliding Window 中位数怎么做？ {#fu-34-25}&quot;">​</a></h5><p><strong>答</strong>：窗口滑动需删除离开元素，普通堆不支持随机删，可用两棵「延迟删除」堆或平衡 BST（TreeSet+计数）/有序数组+二分，复杂度约 O(log n) 每步。</p><h5 id="fu-34-26" tabindex="-1">追问2：双堆能否直接支持求第 K 小？ <a class="header-anchor" href="#fu-34-26" aria-label="Permalink to &quot;追问2：双堆能否直接支持求第 K 小？ {#fu-34-26}&quot;">​</a></h5><p><strong>答</strong>：不能直接。第 K 小通常用两个堆维护大小为 K 的小顶+其余，或用快速选择；双堆专为中位数（即第 n/2 小）设计。</p><h3 id="q-34-14" tabindex="-1">14. 并查集：计算二维网格中岛屿数量（200. Number of Islands 的并查集解法，并说明路径压缩与按秩合并）。 <a class="header-anchor" href="#q-34-14" aria-label="Permalink to &quot;14. 并查集：计算二维网格中岛屿数量（200. Number of Islands 的并查集解法，并说明路径压缩与按秩合并）。 {#q-34-14}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：Union-Find、连通分量、路径压缩。</p><p><strong>参考答案</strong>：将陆地格映射为一维 id <code>i*m+j</code>，初始化每格父为自身，陆地数计为陆地格数。遍历每个陆地，对上下左右陆地 <code>union</code>；union 时若根不同则合并并把计数 -1。查根 <code>find</code> 时路径压缩：<code>while(p!=parent[p]){ parent[p]=parent[parent[p]]; p=parent[p]; } return p;</code>。按秩合并：维护 rank/size，把小树挂大树下降低高度。</p><p><strong>深度解析</strong>：时间近乎 O(n<em>m α(n))（α 反阿克曼，近似常数），空间 O(n</em>m)。相比 DFS/BFS Flood Fill，并查集适合动态增删连通性的场景（如离线查询）。注意边界越界检查。</p><p><strong>易错点</strong>：忘记路径压缩使 find 退化为 O(n)；合并未维护计数；网格坐标映射错误；重复 union 同一对导致多减。</p><h4 id="f-34-14" tabindex="-1">追问： <a class="header-anchor" href="#f-34-14" aria-label="Permalink to &quot;追问： {#f-34-14}&quot;">​</a></h4><h5 id="fu-34-27" tabindex="-1">追问1：路径压缩与按秩合并能否同时用？ <a class="header-anchor" href="#fu-34-27" aria-label="Permalink to &quot;追问1：路径压缩与按秩合并能否同时用？ {#fu-34-27}&quot;">​</a></h5><p><strong>答</strong>：可以且推荐同时用，两者互补：路径压缩压平树，按秩合并保持浅树，联合后单次操作均摊 O(α(n))，几乎线性。</p><h5 id="fu-34-28" tabindex="-1">追问2：岛屿数量用 DFS 与并查集哪个好？ <a class="header-anchor" href="#fu-34-28" aria-label="Permalink to &quot;追问2：岛屿数量用 DFS 与并查集哪个好？ {#fu-34-28}&quot;">​</a></h5><p><strong>答</strong>：静态图 DFS/BFS 更简单 O(n*m)；若后续有动态撤销/连通查询（如「被围绕的区域」「账户合并」），并查集更自然。</p><h3 id="q-34-15" tabindex="-1">15. 拓扑排序：课程表——判断能否修完所有课程（先修依赖成环则不可）。 <a class="header-anchor" href="#q-34-15" aria-label="Permalink to &quot;15. 拓扑排序：课程表——判断能否修完所有课程（先修依赖成环则不可）。 {#q-34-15}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：拓扑排序、BFS（Kahn）、DFS 判环、入度。</p><p><strong>参考答案</strong>：建图：课程为点，依赖边 <code>pre-&gt;cur</code>。计算入度，入度 0 入队列。BFS：每次出队并把它指向节点的入度 -1，归零再入队；统计出队数 == n 则可修完（无环）。Java 用 <code>int[] indeg</code> 与 <code>Queue</code>。DFS 法：三色标记（未访问/访问中/已完），遇访问中即环。</p><p><strong>深度解析</strong>：Kahn O(V+E)、空间 O(V+E)。BFS 还能直接产出拓扑序；DFS 更易检测后向边判环。两者等价，面试任选并讲清。注意依赖可能重复（用 Set 边去重避免入度虚高）。</p><p><strong>易错点</strong>：入度统计漏边或重复边；队列空但出队数 &lt; n 误判可修；DFS 三色状态切换错误。</p><h4 id="f-34-15" tabindex="-1">追问： <a class="header-anchor" href="#f-34-15" aria-label="Permalink to &quot;追问： {#f-34-15}&quot;">​</a></h4><h5 id="fu-34-29" tabindex="-1">追问1：如何输出一种合法的修课顺序？ <a class="header-anchor" href="#fu-34-29" aria-label="Permalink to &quot;追问1：如何输出一种合法的修课顺序？ {#fu-34-29}&quot;">​</a></h5><p><strong>答</strong>：Kahn 算法出队顺序本身就是拓扑序，直接收集即可；若要求字典序最小可在入度 0 时用优先队列。</p><h5 id="fu-34-30" tabindex="-1">追问2：依赖有重复边怎么处理？ <a class="header-anchor" href="#fu-34-30" aria-label="Permalink to &quot;追问2：依赖有重复边怎么处理？ {#fu-34-30}&quot;">​</a></h5><p><strong>答</strong>：建邻接表前用 <code>Set&lt;Pair&gt;</code> 去重，或在入度统计时仅对首次出现的边 +1，避免入度虚高导致误判不可修。</p><h3 id="q-34-16" tabindex="-1">16. 二分查找：在旋转排序数组中搜索目标值（如 [4,5,6,7,0,1,2] 找 target）。 <a class="header-anchor" href="#q-34-16" aria-label="Permalink to &quot;16. 二分查找：在旋转排序数组中搜索目标值（如 [4,5,6,7,0,1,2] 找 target）。 {#q-34-16}&quot;">​</a></h3><p><strong>难度</strong>：★★</p><p><strong>考点</strong>：二分、边界判定、旋转数组。</p><p><strong>参考答案</strong>：标准左闭右闭 <code>while(l&lt;=r)</code>。取 <code>mid</code>，若 <code>nums[mid]==target</code> 返回。判断哪半有序：若 <code>nums[l]&lt;=nums[mid]</code>（左半有序），则 <code>target</code> 在 <code>[l,mid)</code> 当 <code>nums[l]&lt;=target&lt;nums[mid]</code> 否则右半；否则右半有序，类似判断。收缩边界。找不到返回 -1。Java 注意用 <code>l + (r-l)/2</code> 防溢出。</p><p><strong>深度解析</strong>：时间 O(log n)、空间 O(1)。关键点是将区间分为「有序半」与「可能含旋转半」，只在有序半内用常规二分判断。变种：找旋转点（最小值）、允许重复（[1,1,1,0,1] 需 <code>l++</code> 退化 O(n)）。</p><p><strong>易错点</strong>：<code>nums[l]&lt;=nums[mid]</code> 漏等号导致边界漏；<code>target</code> 比较区间边界开闭错；<code>mid</code> 计算溢出（用 <code>(l+r)&gt;&gt;&gt;1</code>）。</p><h4 id="f-34-16" tabindex="-1">追问： <a class="header-anchor" href="#f-34-16" aria-label="Permalink to &quot;追问： {#f-34-16}&quot;">​</a></h4><h5 id="fu-34-31" tabindex="-1">追问1：若数组含大量重复元素如何处理？ <a class="header-anchor" href="#fu-34-31" aria-label="Permalink to &quot;追问1：若数组含大量重复元素如何处理？ {#fu-34-31}&quot;">​</a></h5><p><strong>答</strong>：无法用 <code>&lt;=</code> 判断有序半时（如 <code>nums[l]==nums[mid]==nums[r]</code>），只能 <code>l++/r--</code> 收缩，最坏退化为 O(n)，这是重复导致的固有代价。</p><h5 id="fu-34-32" tabindex="-1">追问2：如何找旋转数组的最小值（无 target）？ <a class="header-anchor" href="#fu-34-32" aria-label="Permalink to &quot;追问2：如何找旋转数组的最小值（无 target）？ {#fu-34-32}&quot;">​</a></h5><p><strong>答</strong>：二分：<code>if(nums[mid]&gt;nums[r])</code> 最小值在右半 <code>l=mid+1</code>；否则 <code>r=mid</code>。最后 <code>nums[l]</code> 即最小，时间 O(log n)。</p><h3 id="q-34-17" tabindex="-1">17. 动态规划：0/1 背包——给定重量与价值，容量 W 下最大价值；并说明空间优化。 <a class="header-anchor" href="#q-34-17" aria-label="Permalink to &quot;17. 动态规划：0/1 背包——给定重量与价值，容量 W 下最大价值；并说明空间优化。 {#q-34-17}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：DP 状态定义、状态转移、滚动数组。</p><p><strong>参考答案</strong>：状态 <code>dp[i][w]</code> 前 i 件容量 w 最大价值。转移：<code>dp[i][w]=max(dp[i-1][w], dp[i-1][w-wt[i]]+val[i])</code>（w≥wt[i]）。空间优化为一维数组从后往前更新：<code>for(i) for(w=W; w&gt;=wt[i]; w--) dp[w]=max(dp[w], dp[w-wt[i]]+val[i]);</code> 倒序保证每件只用一次。完全背包则正序。返回 <code>dp[W]</code>。</p><p><strong>深度解析</strong>：二维 O(nW)、优化后 O(W)。倒序是关键：避免同一物品重复选取。若需输出方案，可回溯 <code>dp</code> 或用 <code>bool</code> 表记录选否。注意 W 很大（如 1e9）时空间爆炸，需换价值维度 DP。</p><p><strong>易错点</strong>：一维数组正序写成完全背包；容量边界 <code>w&gt;=wt[i]</code> 漏判；初始化 <code>dp[0]=0</code> 其余 0（恰好装满需 -∞）；物品重量超 W 未跳过。</p><h4 id="f-34-17" tabindex="-1">追问： <a class="header-anchor" href="#f-34-17" aria-label="Permalink to &quot;追问： {#f-34-17}&quot;">​</a></h4><h5 id="fu-34-33" tabindex="-1">追问1：如何输出具体选了哪些物品？ <a class="header-anchor" href="#fu-34-33" aria-label="Permalink to &quot;追问1：如何输出具体选了哪些物品？ {#fu-34-33}&quot;">​</a></h5><p><strong>答</strong>：用二维 dp 或额外 <code>choose[i][w]</code> 记录是否选取，从 <code>dp[n][W]</code> 反向回溯：若 <code>dp[i][w]!=dp[i-1][w]</code> 说明选了第 i 件，W 减 <code>wt[i]</code>，否则 i-1。</p><h5 id="fu-34-34" tabindex="-1">追问2：完全背包与 0/1 背包仅差遍历方向，为什么？ <a class="header-anchor" href="#fu-34-34" aria-label="Permalink to &quot;追问2：完全背包与 0/1 背包仅差遍历方向，为什么？ {#fu-34-34}&quot;">​</a></h5><p><strong>答</strong>：正序更新时 <code>dp[w-wt[i]]</code> 已是本层（含当前物品）的值，故可重复选；倒序时引用的是上一层旧值，保证每件只选一次。</p><h3 id="q-34-18" tabindex="-1">18. 回溯：生成全排列（含去重）、子集、N 皇后，说明剪枝与回溯模板。 <a class="header-anchor" href="#q-34-18" aria-label="Permalink to &quot;18. 回溯：生成全排列（含去重）、子集、N 皇后，说明剪枝与回溯模板。 {#q-34-18}&quot;">​</a></h3><p><strong>难度</strong>：★★★</p><p><strong>考点</strong>：回溯、DFS 状态树、剪枝、位运算。</p><p><strong>参考答案</strong>：全排列：<code>used[]</code> 标记已选，<code>dfs(path)</code> 每层选未用元素加入，到底收集，回退 <code>used[i]=false</code>。有重复元素先排序，同层相同值且前一未用则剪枝（<code>i&gt;0&amp;&amp;nums[i]==nums[i-1]&amp;&amp;!used[i-1]</code>）。子集：每步选/不选，<code>start</code> 避免重复组合。N 皇后：每行放皇后，用三个布尔集（列、主对角线 <code>r-c</code>、副对角线 <code>r+c</code>）剪枝，递归到行末收集解。</p><p><strong>深度解析</strong>：全排列 O(n·n!)（含复制），子集 2^n，N 皇后受剪枝约束远小于 n^n。回溯核心是「做选择—递归—撤销」。可用位运算加速皇后（bitmask 记录可用列）。注意结果去重与浅拷贝（Java 需 <code>new ArrayList(path)</code>）。</p><p><strong>易错点</strong>：回退时忘记恢复状态（used/path）；去重未先排序；N 皇后对角线索引 <code>r-c</code> 可能为负需 <code>+n</code> 偏移；收集解时直接加引用导致全空。</p><h4 id="f-34-18" tabindex="-1">追问： <a class="header-anchor" href="#f-34-18" aria-label="Permalink to &quot;追问： {#f-34-18}&quot;">​</a></h4><h5 id="fu-34-35" tabindex="-1">追问1：如何用位运算优化 N 皇后？ <a class="header-anchor" href="#fu-34-35" aria-label="Permalink to &quot;追问1：如何用位运算优化 N 皇后？ {#fu-34-35}&quot;">​</a></h5><p><strong>答</strong>：用整数 <code>cols/diag1/diag2</code> 的位表示占用，可用位置 <code>avail = ((1&lt;&lt;n)-1) &amp; ~(cols|diag1|diag2)</code>，循环取最低位 <code>p=avail&amp;-avail</code> 放置并递归，位运算快且省数组。</p><h5 id="fu-34-36" tabindex="-1">追问2：子集与组合（组合总和）回溯区别？ <a class="header-anchor" href="#fu-34-36" aria-label="Permalink to &quot;追问2：子集与组合（组合总和）回溯区别？ {#fu-34-36}&quot;">​</a></h5><p><strong>答</strong>：子集枚举每个元素选/不选（幂集）；组合总和在候选上按 <code>start</code> 递增选取且可重复使用（完全背包式），或不可重复（0/1），重点在 start 指针控制不回头以去重。</p>',199)])])}const g=e(n,[["render",d]]);export{u as __pageData,g as default};
